options.onRender:
(() => {
  const root = htmlNode.querySelector('#root');
  if (!root) return;
  if (!data?.series?.length) { root.innerHTML = `<div style='padding:40px;color:#666;text-align:center'>Aguardando dados...</div>`; return; }
  const fields = {};
  data.series.forEach(s => s.fields?.forEach(f => { if (!fields[f.name]) fields[f.name] = { values: f.values?.toArray ? f.values.toArray() : (f.values||[]) }; }));
  const rowCount = Math.max(...Object.values(fields).map(f=>f.values.length),0);
  const rows = [];
  for (let i=0;i<rowCount;i++) { const r={}; Object.keys(fields).forEach(k=>r[k]=fields[k].values[i]); rows.push(r); }
  const online = rows.filter(r=>r.agent_status==='online').length;
  const offline = rows.filter(r=>['offline','never_seen'].includes(r.agent_status)).length;
  const stale = rows.filter(r=>r.agent_status==='stale').length;
  const statusColor = s => s==='online'?'#00C851':s==='stale'?'#ffbb33':'#ff4444';
  const statusLabel = s => s==='online'?'ONLINE':s==='stale'?'INSTÁVEL':'OFFLINE';
  const statusAnim = s => s==='online'?'pulse-green':s==='stale'?'pulse-yellow':'pulse-red';
  const fmtCpu = v => { const n=Number(v); if(isNaN(n)||v==null) return `<span style='color:#666'>N/A</span>`; const c=n>=95?'#ff4444':n>=80?'#ffbb33':'#00C851'; return `<span style='color:${c};font-weight:600'>${n.toFixed(1)}%</span>`; };
  const fmtRam = v => { const n=Number(v); if(isNaN(n)||v==null) return `<span style='color:#666'>N/A</span>`; const c=n>=95?'#ff4444':n>=85?'#ffbb33':'#00C851'; return `<span style='color:${c};font-weight:600'>${n.toFixed(1)}%</span>`; };
  const fmtTime = v => { if(!v) return 'N/A'; try { return new Date(v).toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}); } catch { return v; } };
  root.innerHTML = `
  <style>
    .wrap{padding:16px;animation:fadeIn .4s ease}
    .kpis{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-bottom:16px}
    .kpi{background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.07);border-radius:14px;padding:16px 20px}
    .kpi-val{font-size:32px;font-weight:800;color:#e9eefc;line-height:1}
    .kpi-lbl{font-size:12px;color:rgba(220,230,255,.55);font-weight:600;margin-top:4px;text-transform:uppercase;letter-spacing:.5px}
    .kpi.ok{border-left:4px solid #00C851}.kpi.warn{border-left:4px solid #ffbb33}.kpi.crit{border-left:4px solid #ff4444}.kpi.info{border-left:4px solid #667eea}
    .table-wrap{background:rgba(255,255,255,.02);border:1px solid rgba(255,255,255,.06);border-radius:14px;overflow:hidden}
    .thead{display:grid;grid-template-columns:2fr 1fr 1fr 1fr 1fr 1fr;padding:12px 20px;background:rgba(10,12,30,.9);font-size:11px;font-weight:700;color:rgba(220,230,255,.7);text-transform:uppercase;letter-spacing:.5px;border-bottom:1px solid rgba(255,255,255,.07)}
    .trow{display:grid;grid-template-columns:2fr 1fr 1fr 1fr 1fr 1fr;padding:13px 20px;border-bottom:1px solid rgba(255,255,255,.03);align-items:center}
    .trow:hover{background:rgba(255,255,255,.03)}.trow:last-child{border-bottom:none}
    .host-cell{display:flex;align-items:center;gap:10px}
    .dot{width:10px;height:10px;border-radius:50%;flex-shrink:0}
    .host-name{font-weight:600;color:#e9eefc;font-size:13px}
    .host-sub{font-size:11px;color:rgba(220,230,255,.45);margin-top:1px}
    .badge{display:inline-block;padding:3px 10px;border-radius:20px;font-size:11px;font-weight:700}
    .cell{font-size:13px;color:#e9eefc}
    .dns-ok{color:#00C851;font-weight:600}.dns-off{color:#ff4444;font-weight:600}
    .ts{font-size:12px;color:rgba(220,230,255,.5)}
  </style>
  <div class='wrap'>
    <div class='kpis'>
      <div class='kpi ok'><div class='kpi-val'>${online}</div><div class='kpi-lbl'>Online</div></div>
      <div class='kpi ${stale>0?'warn':'info'}'><div class='kpi-val'>${stale}</div><div class='kpi-lbl'>Instável</div></div>
      <div class='kpi ${offline>0?'crit':'info'}'><div class='kpi-val'>${offline}</div><div class='kpi-lbl'>Offline</div></div>
      <div class='kpi info'><div class='kpi-val'>${rows.length}</div><div class='kpi-lbl'>Total</div></div>
    </div>
    <div class='table-wrap'>
      <div class='thead'><div>Host</div><div>Status</div><div>CPU</div><div>RAM</div><div>DNS</div><div>Último contato</div></div>
      ${rows.map(r=>`
        <div class='trow'>
          <div class='host-cell'>
            <div class='dot' style='background:${statusColor(r.agent_status)};animation:${statusAnim(r.agent_status)} 2s infinite'></div>
            <div><div class='host-name'>${r.hostname}</div>${r.display_name?`<div class='host-sub'>${r.display_name}${r.location?' · '+r.location:''}</div>`:''}</div>
          </div>
          <div><span class='badge' style='background:${statusColor(r.agent_status)}22;color:${statusColor(r.agent_status)}'>${statusLabel(r.agent_status)}</span></div>
          <div class='cell'>${fmtCpu(r.cpu_percent)}</div>
          <div class='cell'>${fmtRam(r.ram_percent)}</div>
          <div class='cell'>${(!r.dns_service_name || r.dns_service_name === 'unknown') ? "<span style='color:#ff4444;font-weight:600'>✗ N/D</span>" : r.dns_service_active ? "<span style='color:#00C851;font-weight:600'>" + r.dns_service_name + " ✓</span>" : "<span style='color:#ffbb33;font-weight:600'>" + r.dns_service_name + " ⏸</span>"}</div>
          <div class='ts'>${fmtTime(r.last_seen)}</div>
        </div>`).join('')}
    </div>
  </div>`;
})();

