    </div>
    <div class='list'>
      ${rows.length===0
        ? `<div class='empty'><span style='font-size:28px'>✅</span><span>Sem falhas nas últimas 24h</span></div>`
        : rows.map(r=>`
          <div class='item'>
            <div>
              <div class='item-top'>
                <span class='err-badge' style='background:${errColor(r.error_code)}22;color:${errColor(r.error_code)}'>${r.error_code||'ERRO'}</span>
